// ─── Customs-Critical Commodity Symbols ───
// Focus on commodities relevant to customs risk assessment
// Mapped to HS codes where applicable

const CUSTOMS_COMMODITIES = [
  // Semiconductors (HS 8542)
  { symbol: 'SOXX', name: 'Semiconductor Index', hsCode: '8542', category: 'Semiconductors', sensitivity: 0.95 },
  // Nickel & Critical Metals (HS 7501-7508)
  { symbol: 'NI=F', name: 'Nickel Futures', hsCode: '7502', category: 'Critical Metals', sensitivity: 0.85 },
  { symbol: 'HG=F', name: 'Copper Futures', hsCode: '7403', category: 'Critical Metals', sensitivity: 0.80 },
  { symbol: 'ALI=F', name: 'Aluminum Futures', hsCode: '7601', category: 'Critical Metals', sensitivity: 0.75 },
  // Oil & Gas (HS 2709-2711)
  { symbol: 'CL=F', name: 'WTI Crude Oil', hsCode: '2709', category: 'Energy', sensitivity: 0.90 },
  { symbol: 'BZ=F', name: 'Brent Crude', hsCode: '2709', category: 'Energy', sensitivity: 0.90 },
  { symbol: 'NG=F', name: 'Natural Gas', hsCode: '2711', category: 'Energy', sensitivity: 0.85 },
  // Agricultural / Grain (HS 1001-1005)
  { symbol: 'ZW=F', name: 'Wheat Futures', hsCode: '1001', category: 'Agriculture', sensitivity: 0.75 },
  { symbol: 'ZC=F', name: 'Corn Futures', hsCode: '1005', category: 'Agriculture', sensitivity: 0.70 },
  { symbol: 'ZS=F', name: 'Soybean Futures', hsCode: '1201', category: 'Agriculture', sensitivity: 0.70 },
  // Fertilizers (HS 3105)
  { symbol: 'MOS', name: 'Mosaic (Fertilizers)', hsCode: '3105', category: 'Fertilizers', sensitivity: 0.75 },
  { symbol: 'NTR', name: 'Nutrien (Fertilizers)', hsCode: '3105', category: 'Fertilizers', sensitivity: 0.75 },
  // Gold (HS 7108)
  { symbol: 'GC=F', name: 'Gold Futures', hsCode: '7108', category: 'Precious Metals', sensitivity: 0.70 },
  // Pharmaceuticals (HS 3004)
  { symbol: 'XLV', name: 'Healthcare ETF', hsCode: '3004', category: 'Pharmaceuticals', sensitivity: 0.70 },
];

return CUSTOMS_COMMODITIES.map(c => ({ json: c }));

// Parse Yahoo Finance chart response and enrich with customs metadata
const commodity = $('Define Customs Commodities').item.json;
const data = $input.item.json;

const result = data?.chart?.result?.[0];
const meta = result?.meta;

if (!meta) {
  return { json: { ...commodity, price: null, change: null, error: 'no data' } };
}

const price = meta.regularMarketPrice;
const prevClose = meta.chartPreviousClose || meta.previousClose || price;
const change = prevClose ? Math.round(((price - prevClose) / prevClose) * 10000) / 100 : 0;
const closes = result?.indicators?.quote?.[0]?.close || [];
const sparkline = closes.filter(v => v != null);

// Volatility signal (simplistic: daily range vs average)
const high = meta.regularMarketDayHigh || price;
const low = meta.regularMarketDayLow || price;
const dayRange = high - low;
const volatility = price > 0 ? Math.round((dayRange / price) * 10000) / 100 : 0;

// Trade alert threshold
const absChange = Math.abs(change);
let alertLevel = 'normal';
if (absChange >= 5) alertLevel = 'critical';
else if (absChange >= 3) alertLevel = 'elevated';
else if (absChange >= 1.5) alertLevel = 'moderate';

return {
  json: {
    symbol: commodity.symbol,
    name: commodity.name,
    hsCode: commodity.hsCode,
    category: commodity.category,
    sensitivity: commodity.sensitivity,
    price,
    change,
    volatility,
    alertLevel,
    sparkline: sparkline.slice(-20),
    fetchedAt: new Date().toISOString(),
  }
};

// Aggregate all commodity quotes into final payload
const quotes = $input.all().map(i => i.json).filter(q => q.price != null);

// Group by category
const byCategory = {};
for (const q of quotes) {
  if (!byCategory[q.category]) byCategory[q.category] = [];
  byCategory[q.category].push(q);
}

// Identify elevated commodities for customs alerting
const elevated = quotes.filter(q => q.alertLevel !== 'normal');

return [{
  json: {
    source: 'yahoo-finance',
    pipeline: 'commodity-customs-tracker',
    quotes,
    byCategory,
    alerts: elevated,
    summary: {
      total: quotes.length,
      critical: elevated.filter(q => q.alertLevel === 'critical').length,
      elevated: elevated.filter(q => q.alertLevel === 'elevated').length,
      moderate: elevated.filter(q => q.alertLevel === 'moderate').length,
    },
    processedAt: new Date().toISOString(),
  }
}];
